CODE_EXAMPLE:
// Before (smell - same calculation in two places)
class SalesReport {
  double getDiscount() {
    return total * 0.1;
  }
}

class InvoiceReport {
  double getDiscount() {
    return total * 0.1; // duplicate
  }
}

// After (refactored)
class Report {
  double getDiscount() {
    return total * 0.1;
  }
}

class SalesReport extends Report {}
class InvoiceReport extends Report {}

UNIT_TEST_EXAMPLE:
@Test
public void testDuplicateCode() {
  Report salesReport = new SalesReport(100);
  Report invoiceReport = new InvoiceReport(100);
  assertEquals(salesReport.getDiscount(), invoiceReport.getDiscount(), 0.01);
}
